css:
.loader {color: var(--loader-color, #db2777);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.loader:before {content: "";
  border: 8px solid var(--loader-color, #db2777);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: l1 infinite 1s steps(4,jump-none);
}@keyframes l1 {0% {width: 0% }to {width: 75%}}
